<template><div class="shell lab-shell"><aside class="sidebar"><div class="brand"><div class="brand-mark"><el-icon><DataAnalysis/></el-icon></div><div><small>NEUSOFT MEDICAL</small><strong>云脑智慧检验</strong></div></div><nav><p>检验工作区</p><router-link v-for="item in menus" :key="item.path" :to="item.path"><el-icon><component :is="item.icon"/></el-icon><span>{{item.label}}</span></router-link></nav><div class="side-help"><el-icon><CircleCheckFilled/></el-icon><div><strong>报告质量规范</strong><span>准确、完整、及时、可追溯</span></div></div></aside><main><header><div><h2>{{currentTitle}}</h2><p>{{today}}</p></div><div class="head-actions"><button class="notify"><el-icon><Bell/></el-icon><i></i></button><div class="staff"><span>{{auth.user?.name?.slice(0,1)||'检'}}</span><div><strong>{{auth.user?.name||'检验人员'}}</strong><small>检验科工作站</small></div></div><el-dropdown @command="handleCommand"><button class="more"><el-icon><ArrowDown/></el-icon></button><template #dropdown><el-dropdown-menu><el-dropdown-item command="profile">个人中心</el-dropdown-item><el-dropdown-item command="logout" divided>退出登录</el-dropdown-item></el-dropdown-menu></template></el-dropdown></div></header><section class="page"><router-view/></section></main></div></template>
<script setup lang="ts">import{computed,onMounted}from'vue';import{useRoute,useRouter}from'vue-router';import{DataAnalysis,CircleCheckFilled,Bell,ArrowDown,DataBoard,Document,Clock,Collection,User,MagicStick}from'@element-plus/icons-vue';import{useAuthStore}from'@/stores/auth';const route=useRoute(),router=useRouter(),auth=useAuthStore();const menus=[{path:'/dashboard',label:'检验总览',icon:DataBoard},{path:'/pending',label:'待检查队列',icon:Document},{path:'/history',label:'报告记录',icon:Clock},{path:'/ai-review',label:'AI智能审核',icon:MagicStick},{path:'/items',label:'检查项目',icon:Collection},{path:'/profile',label:'个人中心',icon:User}];const currentTitle=computed(()=>menus.find(x=>x.path===route.path)?.label||'智慧检验');const today=new Intl.DateTimeFormat('zh-CN',{year:'numeric',month:'long',day:'numeric',weekday:'long'}).format(new Date());const handleCommand=(c:string)=>{if(c==='logout'){auth.signOut();router.replace('/login')}else router.push('/profile')};onMounted(()=>auth.loadUser())</script>
